import os
import json
import datetime
from typing import List, Dict, Any
from reports.formatter import format_report
from reports.utils import calculate_totals

ALLOWED_REPORT_TYPES = {'sales', 'inventory', 'users', 'revenue'}


class ReportGenerator:
    def __init__(self, db_url=None):
        self.db_url = db_url or os.environ.get('DATABASE_URL', '')
        if not self.db_url:
            raise ValueError('DATABASE_URL not configured')

    def generate(self, report_type: str, params: dict) -> dict:
        data = self._fetch_data(report_type, params)
        totals = calculate_totals(data)
        return format_report(report_type, data, totals)

    def _fetch_data(self, report_type: str, params: dict):
        if report_type not in ALLOWED_REPORT_TYPES:
            raise ValueError(f'Invalid report type: {report_type}')
        import psycopg2
        table = f'{report_type}_data'
        with psycopg2.connect(self.db_url) as conn:
            with conn.cursor() as cursor:
                cursor.execute(
                    f'SELECT * FROM {table} WHERE date >= %s',
                    (params['start_date'],)
                )
                return cursor.fetchall()

def calculate_totals(data):
    totals = {}
    for row in data:
        for key, val in row.items():
            if isinstance(val, (int, float)):
                totals[key] = totals.get(key, 0) + val
    return totals
